import{_ as i,o as a,c as t,a2 as o}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse(`{"title":"Migrazione da un'installazione Spatie esistente","description":"","frontmatter":{},"headers":[],"relativePath":"it/guide/migration.md","filePath":"it/guide/migration.md"}`),s={name:"it/guide/migration.md"};function l(n,e,r,d,c,p){return a(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="migrazione-da-un-installazione-spatie-esistente" tabindex="-1">Migrazione da un&#39;installazione Spatie esistente <a class="header-anchor" href="#migrazione-da-un-installazione-spatie-esistente" aria-label="Permalink to &quot;Migrazione da un&#39;installazione Spatie esistente&quot;">​</a></h1><p>Se la tua applicazione usa già <code>spatie/laravel-permission</code> con ruoli, permessi e assegnazioni esistenti, <code>clearance:install</code> li rileva e li preserva - non esegue mai le migrazioni di Spatie se la tabella <code>roles</code> esiste già. Vedi <a href="/clearance-docs/it/guide/installation.html">Installazione</a> per il flusso completo di installazione.</p><p>Una volta installato, usa <code>clearance:backfill</code> per applicare i metadati propri di Clearance ai tuoi ruoli e guardie esistenti.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # meta + role scope + guards</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --only=meta</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # just one section</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # preview, no writes</span></span></code></pre></div><h2 id="cosa-fa-ogni-sezione" tabindex="-1">Cosa fa ogni sezione <a class="header-anchor" href="#cosa-fa-ogni-sezione" aria-label="Permalink to &quot;Cosa fa ogni sezione&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sezione</th><th>Effetto</th></tr></thead><tbody><tr><td><code>meta</code></td><td>Genera un nome visualizzato <code>clr_meta</code> (nome del ruolo in title-case) per ogni ruolo che non ne ha uno.</td></tr><tr><td><code>roles</code></td><td>Genera i valori predefiniti di <code>clr_role_meta</code> (<code>scope=global</code>, <code>is_locked=false</code>) per ogni ruolo che non ne ha uno.</td></tr><tr><td><code>guards</code></td><td>Importa le guardie da <code>config(&#39;auth.guards&#39;)</code> in <code>clr_guards</code>, filtrate da <code>allowed_guard_drivers</code>.</td></tr></tbody></table><p>Usa <code>--only=&lt;section&gt;</code> per eseguire una singola sezione invece di tutte e tre.</p><div class="tip custom-block"><p class="custom-block-title">Idempotente</p><p>Tutte le sezioni sono idempotenti - ri-eseguire <code>clearance:backfill</code> è sicuro e non duplicherà né sovrascriverà le righe <code>clr_*</code> esistenti.</p></div><h2 id="casi-limite" tabindex="-1">Casi limite <a class="header-anchor" href="#casi-limite" aria-label="Permalink to &quot;Casi limite&quot;">​</a></h2><p>Il repository del pacchetto contiene una guida di migrazione più approfondita che copre casi limite non riassunti qui - in particolare cosa succede quando il tuo database ha già un ruolo chiamato <code>super_admin</code> (o un alias come <code>superadmin</code>, <code>root</code>, <code>owner</code>) che entra in collisione con il ruolo <code>super_admin</code> proprio di Clearance, e note sulle sottoclassi personalizzate dei modelli <code>Role</code>/<code>Permission</code> e sul comportamento di importazione delle guardie. Leggila prima di eseguire il backfill su un database di produzione con dati di ruolo esistenti non banali. Vedi anche <a href="/clearance-docs/it/features/super-admin.html">Super Admin</a> per il comportamento di rilevamento degli alias durante <code>clearance:install</code>.</p><h2 id="correlati" tabindex="-1">Correlati <a class="header-anchor" href="#correlati" aria-label="Permalink to &quot;Correlati&quot;">​</a></h2><ul><li><a href="/clearance-docs/it/guide/installation.html">Installazione</a> - il flusso completo di <code>clearance:install</code></li><li><a href="/clearance-docs/it/api/artisan-commands.html">Comandi Artisan</a> - riferimento completo dei comandi</li><li><a href="/clearance-docs/it/guide/architecture.html">Architettura</a> - le tabelle <code>clr_*</code> che il backfill popola</li></ul>`,12)])])}const m=i(s,[["render",l]]);export{u as __pageData,m as default};
